import React, { useState } from 'react';
import './EditPurchase.css';

const EditPurchase = ({ purchase, handleUpdate }) => {
    const [updatedPurchase, setUpdatedPurchase] = useState({ ...purchase });
  
    const handleChange = (e) => {
      const { name, value } = e.target;
      setUpdatedPurchase((prevPurchase) => ({
        ...prevPurchase,
        [name]: value,
      }));
    };
  
    const handleSubmit = (e) => {
      e.preventDefault();
      handleUpdate(updatedPurchase);
    };
  
    return (
    <form onSubmit={handleSubmit} className='add-purchase-form'>
      <div>
        <label>Location:</label>
        <select name="location" value={updatedPurchase.location} onChange={handleChange} required>
          <option value="">Select a location</option>
          {locations.map((location) => (
            <option key={location.id} value={location.id}>
              {location.locationname}
            </option>
          ))}
        </select>
      </div>
      <div>
        <label>Material ID:</label>
        <input type="text" name="materialid" value={updatedPurchase.materialid} onChange={handleChange} required />
      </div>
      <div>
        <label>Material Name:</label>
        <input type="text" name="materialname" value={updatedPurchase.materialname} readOnly required />
      </div>
      {showExtras && (
        <div>
          <label>Width:</label>
          <input
            type="text"
            name="width"
            value={updatedPurchase.width}
            onChange={handleChange}
            required
          />
        </div>
      )}
      {showExtras && (
        <div>
          <label>LOT#:</label>
          <input
            type="text"
            name="lotnumber"
            value={updatedPurchase.lotnumber}
            onChange={handleChange}
            required
          />
        </div>
      )}
      <div>
        <label>Quantity:</label>
        <input type="text" name="quantity" value={updatedPurchase.quantity} onChange={handleChange} required />
      </div>
      <div>
        <label>Price:</label>
        <input type="text" name="price" value={updatedPurchase.price} onChange={handleChange} required />
      </div>
      <div>
        <label>Vendor:</label>
        <Select
          options={vendorOptions}
          value={
            newPurchase.vendorname
              ? { value: updatedPurchase.vendorname, label: updatedPurchase.vendorname }
              : null
          }
          onChange={handleVendorChange}
          placeholder="Select a Vendor"
          isSearchable
          required
        />
      </div>
      <button type="submit" className="add_purchase_btn">Add Purchase</button>
    </form>
  );
  
};

export default EditPurchase;
